import React from "react"

class User extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            users: [
                {
                    id: 1,
                    firstname: 'James'
                }
            ]
        }
    }
    render() {
        return (
            <div>
                {this.state.users.map((item) => (
                    <User key={item.id}/>
                ))}
            </div>
        )
    }
}



export default User
